import styled from "styled-components"
import Brand from '../LandingPage/Brand'

import { Link } from 'react-scroll'

const Footer = () => {
  return (
    <FooterContainer>
      <FooterBrand />
      <div style={{  }}>
        <List>
          <ListHeader> Quick Links </ListHeader>
          <li> <LinkStyled to="Home" smooth={true} duration={1000}> Home </LinkStyled> </li>
          <li> <LinkStyled to="Projects" smooth={true} duration={500}> Projects </LinkStyled> </li>
        </List>
        <List>
          <ListHeader> Contact </ListHeader>
          <li> Email@Email.com </li>
          <li> <a href="https://github.com/energywraith" rel="noopener noreferrer"> Github </a> </li>
        </List>
      </div>
      <Copyright> © 2021 Adam Jałocha </Copyright>
    </FooterContainer>
  )
}

const FooterContainer = styled.footer`
  color: white;

  display: grid;
  grid-template-columns: auto 1fr;
  grid-template-rows: 1fr auto;
  row-gap: 2em;
  padding-top: 2em;

  align-items: center;
  justify-content: center;

  @media(max-width: 600px) {
    grid-template-columns: 1fr !important;
    grid-template-rows: auto auto auto;
  }
`

const FooterBrand = styled(Brand)`
  font-size: 1.3em;
  padding: 0 3em;
  width: auto;

  @media(max-width: 600px) {
    display: none;
  }
`

const Copyright = styled.span`
  grid-row: 2;
  grid-column: 1/3;
  text-align: center;
  padding: 1em 0;
  width: 100%;
  border-top: 1px solid #242424;
`

const Lists = styled.div`
  display: flex;
  flex-direction: column;
  column-gap: 5em;
  justify-content: center;
`

const List = styled.ul`
  display: flex;
  flex-direction: column;
  row-gap: 0.5em;
`

const ListHeader = styled.li`
  font-weight: 600;
  font-size: 1.1em;
  margin-bottom: 0.5em;
  letter-spacing: 1px;
`

const LinkStyled = styled(Link)`
  cursor: pointer;
`


export default Footer
